/* ── cached data helper ────────────────────────────────────────
 * Wraps the database call so that every Server Component that
 * consumes product data shares the same cache entry tagged
 * "products".  A single revalidateTag('products') call (see the
 * Server Action below) busts this across all consumers at once.
 */
const getCachedProducts = unstable_cache(
  async () => {
    const products = await getAllProducts();
    return products;
  },
  ['products-list'],
